        windex = None
    else:
        sr = sr.split()
        sr0 = int(sr[0])
        sr1 = int(sr[1])
        windex = range(sr0, sr1 + 1)

    if args.final:
        windex = "final"

    process_outcar_file_v5_dev(
        outcars, data, numbers, types, max_types, windex=windex, fout="test.configs"
