                gamma_param = {"k_points": [1, 1, 1, 0, 0, 0]}
                ret_kpt = make_abacus_scf_kpt(gamma_param)
            else:
                if "k_points" in jdata.keys():
                    ret_kpt = make_abacus_scf_kpt(jdata)
                elif "fp_kpt_file" in jdata.keys():
