                    fk = open(fp_kpt_path)
                    ret_kpt = fk.read()
                    fk.close()
                else:
                    raise RuntimeError("Cannot find any k-points information")
        else:
            if "k_points" in jdata.keys():
                ret_kpt = make_abacus_scf_kpt(jdata)
            elif "fp_kpt_file" in jdata.keys():
                fp_kpt_path = jdata["fp_kpt_file"]
